vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


ret=(texture(sampler_noise_hq,vUv)).xxx;

vec2 mod_uv = vUvOriginal*uTexSize.zw;

vec3 mret = texture( sampler_noise_hq, fract(mod_uv));

vec2 dither_uv = vUvOriginal-texsize_noise_lq.zw;
mret -= (texture(sampler_noise_lq, vUv+dither_uv));

mret += texture( sampler_noise_hq, fract(vUv)).zyx;

mret.x*=.5+.2*sin(vRadius*20+uTime*16)+.1*q12;
mret.y*=.5+.2*sin(vRadius*40+uTime*18.4)+.1*q13;
