/*** Flexis cleaned up Moebius spiral code ***/

float cutoff = 1.1;
int n = 3;
float s = 2;

   vec2 c = (vUv-0.5)*1*uAspect.wz;
   numerator = (c + vec2(q21,q22))*64;
   denominator = c + vec2(q23,q24);
   fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,
                      numerator.y*denominator.x - numerator.x*denominator.y)/
                      (denominator.x*denominator.x + denominator.y*denominator.y);
   c = fraction-0.5;
   float1 ang_hq = n*atan(c.x,c.y);
   vec2 spiral = vec2(ang_hq*q25+q26,s*uAspect.w*log(length(c))+ang_hq*q25+q27);
   spiral = 0.5 + (0.5 - abs( fract( spiral * 0.5 ) * 2.0 - 1.0 ))*cutoff; // mirror

/**********************************************/

vUv=spiral;

vec2 uvm=0;
uvm.x=vUv.x-.07*texture(sampler_noise_hq, vUv.x*1.5+.015*uTime).x;
uvm.y=vUv.y-.07*texture(sampler_noise_hq, vUv.y*1.5+.015*uTime).x;
vUv=uvm;

uvm-=.5;
vec2 uvt = vec2(atan(vUv.x,vUv.y), 1/length(vUv));
uvm+=.5;

//vUv*=uvt;

//You can change the speed and direction of rotation by changing this variable
float rot=1.4;

//This variable defines the center of rotation (cx, cy)
vec2 cxy=vec2(.5,.5);

vec2 xymod=vUv-cxy;
vec2 xy1=0;

//Rotate xy plane
xy1.x=sin(uTime*rot)*xymod.x-cos(uTime*rot)*xymod.y;
xy1.y=cos(uTime*rot)*xymod.x+sin(uTime*rot)*xymod.y;

vec2 rt=(xy1);
vec2 rmod=rt-.5;

vUv=rmod;

vec3 blur = GetBlur1(uvm);
vec3 sharp = texture(sampler_main, uvm);
