vec2 mod = 4*vec2(1*(fix.x)+cos(uvm.x-roam_sin.y*4), 1*(fix.x)-sin(uvm.y+roam_cos.x));

vec3 fret = (fix-blur)-mod.xxx;
fret.x/=fix.y/blur.y;
vec3 inv = 1-fret;
//inv.x=2-inv.y;

float melt = dot(fret, inv);

ret=texture(sampler_main, vUv.xy)*inv+.8*fret;
vec3 modret=mix(ret, inv, 1.5*clamp01(melt));

ret=mix(GetPixel(uvt),modret,.5);
